import { existsSync, readdirSync } from "node:fs";
import { resolve } from "node:path";
import { describe, expect, it } from "vitest";
import { STATIC_PAGES } from "@/lib/static-pages";

// Drift guard: every human-facing page in the (home) route group must appear in
// the sitemap's STATIC_PAGES list, or it ships invisible to crawlers (live 200
// but uncrawlable). This is the exact regression that hid /developers,
// /best-claude-code-plugins, and /claude-agent-sdk-vs-claude-code-plugins after
// #2403 and produced orank's "developer resources invisible to web search" flag.
describe("sitemap covers the (home) route group", () => {
  const homeDir = resolve(__dirname, "../app/(home)");

  function homePaths(dir: string, base = ""): string[] {
    const out: string[] = [];
    for (const entry of readdirSync(dir, { withFileTypes: true })) {
      if (!entry.isDirectory()) continue;
      const sub = resolve(dir, entry.name);
      if (existsSync(resolve(sub, "page.tsx"))) {
        out.push(`${base}/${entry.name}`);
      }
      out.push(...homePaths(sub, `${base}/${entry.name}`));
    }
    return out;
  }

  it("each (home) page path is in STATIC_PAGES", () => {
    for (const p of homePaths(homeDir)) {
      expect(
        (STATIC_PAGES as readonly string[]).includes(p),
        `missing from sitemap STATIC_PAGES: ${p}`,
      ).toBe(true);
    }
  });

  it("STATIC_PAGES has no stale entries (every path still exists on disk)", () => {
    const live = new Set(homePaths(homeDir));
    for (const p of STATIC_PAGES) {
      expect(live.has(p), `STATIC_PAGES lists a path with no page.tsx: ${p}`).toBe(
        true,
      );
    }
  });
});
